import json
with open('baseline-packages.json') as b, open('after-cpm-packages.json') as a:
    baseline = json.load(b)
    after = json.load(a)
    bp = {p['id']: p['resolvedVersion'] for p in baseline['projects'][0]['frameworks'][0]['topLevelPackages']}
    ap = {p['id']: p['resolvedVersion'] for p in after['projects'][0]['frameworks'][0]['topLevelPackages']}
    print('Package comparison (baseline → after):')
    for pkg in sorted(bp):
        status = '✅ unchanged' if bp[pkg] == ap.get(pkg) else f'⚠️  {bp[pkg]} → {ap.get(pkg, \"REMOVED\")}'
        print(f'  {pkg}: {bp[pkg]} {status}')
    for pkg in sorted(set(ap) - set(bp)):
        print(f'  {pkg}: ADDED {ap[pkg]}')
    if bp == ap:
        print('All packages resolve identically. Conversion is version-neutral.')
"

